projectConfigSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "通用弹窗 - 项目级共享配置",
  "type": "object",
  "properties": {
    "modalImage": {
      "type": "string",
      "format": "image",
      "title": "弹窗图片",
      "description": "上传弹窗展示的图片（宽度670px，高度670~890px）",
      "default": "https://uiweb.oss-cn-chengdu.aliyuncs.com/img/通用广告弹窗/默认弹窗.png",
      "ui:options": {
        "accept": "image/*",
        "maxSize": 5242880,
        "minWidth": 670,
        "minHeight": 670,
        "maxWidth": 670,
        "maxHeight": 890
      }
    }
  },
  "required": ["modalImage"]
}
